namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(new[]
        {
            CreateNotification("Welcome to the notifications demo!"),
            CreateNotification("Your profile was updated successfully."),
            CreateNotification("New comment on your post."),
        });
    }

    /// <summary>Returns all notifications available at the time of the call.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>Returns only notifications whose Id is greater than <paramref name="sinceId"/>.</summary>
    public List<Notification> GetSince(int sinceId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > sinceId).ToList();
        }
    }

    /// <summary>
    /// Simulates an external system pushing a new notification.
    /// Called by a background hosted service to keep the demo interesting.
    /// </summary>
    public void AddRandom()
    {
        string[] samples =
        [
            "Deployment completed.",
            "New follower added.",
            "Disk usage above 80%.",
            "Backup finished.",
            "Scheduled task ran successfully.",
            "New sign-in from a new device.",
            "Your subscription will renew soon.",
        ];

        var message = samples[Random.Shared.Next(samples.Length)];

        lock (_lock)
        {
            _notifications.Add(CreateNotification(message));
        }
    }

    private Notification CreateNotification(string message)
        => new(Interlocked.Increment(ref _nextId), message, DateTime.UtcNow);
}

namespace NotificationsApp.Services;

/// <summary>
/// Background hosted service that periodically adds a random notification
/// so there is always new data for the polling loop to discover.
/// </summary>
public class NotificationFeederService(NotificationService notifications) : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(8), stoppingToken);
            notifications.AddRandom();
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationService NotificationSvc

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span style="background:#0d6efd;color:#fff;border-radius:999px;padding:2px 10px;font-size:0.6em;vertical-align:middle;">
        @_notifications.Count
    </span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul>
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li>
                <strong>@n.Timestamp.ToString("HH:mm:ss")</strong> &mdash; @n.Message
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _highWaterMark;

    // Runs during BOTH static SSR and interactive renders.
    // Loads the initial set so the first HTML already contains data.
    protected override void OnInitialized()
    {
        _notifications = NotificationSvc.GetAll();
        _highWaterMark = _notifications.Count == 0 ? 0 : _notifications.Max(n => n.Id);
    }

    // Only fires once per interactive circuit — never during static SSR.
    // This is the safe place to start the polling loop.
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var newer = NotificationSvc.GetSince(_highWaterMark);
            if (newer.Count > 0)
            {
                _notifications.AddRange(newer);
                _highWaterMark = newer.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

